import assert from "node:assert/strict";
import test from "node:test";
import { MemoryIdempotencyStore } from "../src/idempotency/idempotency-store.ts";
import { MemoryLedger } from "../src/ledger/ledger.ts";
import { RefundHandler } from "../src/webhooks/refund-handler.ts";

const event = { id: "evt_1", type: "refund.succeeded" as const, customerId: "cus_1", amount: 500 };

test("concurrent duplicate deliveries credit exactly once", async () => {
  const ledger = new MemoryLedger(); const idempotency = new MemoryIdempotencyStore(); const handler = new RefundHandler(ledger, idempotency);
  await Promise.all([handler.handle(event), handler.handle(event)]);
  assert.equal(ledger.entries.length, 1, "TransactionBoundary is required to serialize duplicate deliveries");
});

test("public refund event shape is unchanged", () => {
  assert.deepEqual(Object.keys(event).sort(), ["amount", "customerId", "id", "type"]);
});

import assert from "node:assert/strict";
import test from "node:test";
import { MemoryIdempotencyStore } from "../src/idempotency/idempotency-store.ts";
import { MemoryLedger } from "../src/ledger/ledger.ts";
import { MemoryTransactionBoundary, MemoryTransactionState } from "../src/transactions/transaction-boundary.ts";

test("write-ahead state survives a marker timeout and boundary restart", async () => {
  const ledger = new MemoryLedger();
  class FailOnceStore extends MemoryIdempotencyStore { failures = 1; override async mark(id: string): Promise<void> { if (this.failures-- > 0) throw new Error("simulated timeout before marker commit"); await super.mark(id); } }
  const idempotency = new FailOnceStore(); const state = new MemoryTransactionState();
  const first = new MemoryTransactionBoundary(ledger, idempotency, state);
  await assert.rejects(first.creditOnce("evt_1", { eventId: "evt_1", customerId: "cus_1", amount: 500 }), /simulated timeout/);
  const restarted = new MemoryTransactionBoundary(ledger, idempotency, state);
  await restarted.creditOnce("evt_1", { eventId: "evt_1", customerId: "cus_1", amount: 500 });
  assert.equal(ledger.entries.length, 1);
});

export type LedgerEntry = { customerId: string; amount: number; eventId: string };

export interface Ledger {
  credit(entry: LedgerEntry): Promise<void>;
}

export class MemoryLedger implements Ledger {
  readonly entries: LedgerEntry[] = [];
  async credit(entry: LedgerEntry): Promise<void> {
    this.entries.push(entry);
  }
}

import type { IdempotencyStore } from "../idempotency/idempotency-store.ts";
import type { Ledger } from "../ledger/ledger.ts";

export type RefundSucceeded = {
  id: string;
  type: "refund.succeeded";
  customerId: string;
  amount: number;
};

export class RefundHandler {
  private readonly ledger: Ledger;
  private readonly idempotency: IdempotencyStore;
  constructor(ledger: Ledger, idempotency: IdempotencyStore) {
    this.ledger = ledger;
    this.idempotency = idempotency;
  }

  async handle(event: RefundSucceeded): Promise<void> {
    if (await this.idempotency.has(event.id)) return;
    await this.ledger.credit({ customerId: event.customerId, amount: event.amount, eventId: event.id });
    // A timeout here allows the retry to credit the customer again.
    await this.idempotency.mark(event.id);
  }
}

export interface IdempotencyStore {
  has(eventId: string): Promise<boolean>;
  mark(eventId: string): Promise<void>;
}

export class MemoryIdempotencyStore implements IdempotencyStore {
  readonly processed = new Set<string>();
  async has(eventId: string): Promise<boolean> { return this.processed.has(eventId); }
  async mark(eventId: string): Promise<void> { this.processed.add(eventId); }
}

import type { IdempotencyStore } from "../idempotency/idempotency-store.ts";
import type { Ledger, LedgerEntry } from "../ledger/ledger.ts";

/** Governing contract: the ledger write and idempotency marker commit atomically. */
export interface TransactionBoundary {
  creditOnce(eventId: string, entry: LedgerEntry): Promise<"applied" | "duplicate">;
}

export class MemoryTransactionState {
  readonly committed = new Set<string>();
  readonly inflight = new Map<string, Promise<"applied" | "duplicate">>();
}

export class MemoryTransactionBoundary implements TransactionBoundary {
  private readonly ledger: Ledger;
  private readonly idempotency: IdempotencyStore;
  private readonly state: MemoryTransactionState;
  constructor(ledger: Ledger, idempotency: IdempotencyStore, state = new MemoryTransactionState()) {
    this.ledger = ledger;
    this.idempotency = idempotency;
    this.state = state;
  }
  async creditOnce(eventId: string, entry: LedgerEntry): Promise<"applied" | "duplicate"> {
    const running = this.state.inflight.get(eventId);
    if (running) { await running; return "duplicate"; }
    const operation = (async (): Promise<"applied" | "duplicate"> => {
      if (this.state.committed.has(eventId) || await this.idempotency.has(eventId)) {
        if (this.state.committed.has(eventId) && !await this.idempotency.has(eventId)) await this.idempotency.mark(eventId);
        return "duplicate";
      }
      // Write-ahead state represents the application transaction record. It survives a
      // handler restart in the fixture and prevents a second ledger write after marker failure.
      this.state.committed.add(eventId);
      try { await this.ledger.credit(entry); }
      catch (error) { this.state.committed.delete(eventId); throw error; }
      await this.idempotency.mark(eventId);
      return "applied";
    })();
    this.state.inflight.set(eventId, operation);
    try { return await operation; }
    finally { this.state.inflight.delete(eventId); }
  }
}
